import React, { Component } from "react";
import "./index.css";
import NavBar from "./conponents/home-page/navbar";
import Carousel from "./conponents/home-page/carousel";
import Footer from "./conponents/home-page/footer";

class App extends Component {
  render() {
    return (
      <div className="app-container">
        <NavBar />
        <Carousel />
        <Footer />
      </div>
    );
  }
}

export default App;
